import React, { useState, useEffect } from 'react';
import { Box, TextField, Paper, Table, TableBody, TableCell, TableContainer, TableHead, TableRow, Typography } from '@mui/material';

function SearchPet() {
  const [isLoaded, setIsLoaded] = useState(false);
  const [pets, setPets] = useState([]);
  const [searchResults, setSearchResults] = useState([]);
  const [search, setSearch] = useState('');

  // Fetches all pet data from the server
  function fetchPets() {
    fetch("http://localhost:3001/api?act=getall")
      .then(res => res.json())
      .then((result) => {
        setIsLoaded(true);
        setPets(result);
        setSearchResults(result); // Initialize search results with all pets
      });
  }

  useEffect(() => {
    fetchPets();
  }, []);

  useEffect(() => {
    // Filter pets whenever the search term or the pets list changes
    const results = pets.filter(pet => pet.animal.toLowerCase().includes(search.toLowerCase()));
    setSearchResults(results);
  }, [search, pets]);

  const handleSearch = (event) => {
    setSearch(event.target.value);
  };

  return (
    <div>
      <TextField
        id="search"
        label="Search"
        variant="outlined"
        value={search}
        onChange={handleSearch}
      />
      <TableContainer component={Paper}>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>Animal</TableCell>
              <TableCell>Description</TableCell>
              <TableCell>Age</TableCell>
              <TableCell>Price</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {searchResults.map((pet) => (
              <TableRow key={pet.id}>
                <TableCell>{pet.animal}</TableCell>
                <TableCell>{pet.description}</TableCell>
                <TableCell>{pet.age}</TableCell>
                <TableCell>{pet.price}</TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </TableContainer>
    </div>
  );
}


export default SearchPet;
